  "code": "def solve(s):
    """The input string s is transformed: letters have their case swapped, and if no letters exist, the string is reversed. The function outputs the transformed string.

    Examples

    solve("1234") = "4321"

    solve("ab") = "AB"

    solve("#a@C") = "#A@c"

    """
    has_letters = any(c.isalpha() for c in s)
    if has_letters:
        return ''.join([c.swapcase() if c.isalpha() else c for c in s])
    else:
        return s[::-1]",
